1	/**
2	 * scan(postcode, trade) — main lead engine entry point.
3	 *
4	 * Pipeline:
5	 *  1. Resolve postcode → outward, region, lat/lon
6	 *  2. Run all sources in parallel (ContractsFinder, FTS, PlanningData, DirectorySignal)
7	 *  3. Normalise raw leads
8	 *  4. Deduplicate by id
9	 *  5. Score and rank
10	 *  6. Return top N with per-source diagnostics
11	 *
12	 * Failover: if source fails (any HTTP error or throw) → log + continue.
13	 * Never blocks on a single source.
14	 */
15	
16	import type { Lead, ScanResult, SourceStats } from './types.ts';
17	import { CONFIG } from './config.ts';
18	import { lookupPostcode } from './postcode.ts';
19	import { contractsFetcher } from './fetchers/contractsFetcher.ts';
20	import { planningDataFetcher } from './fetchers/planningDataFetcher.ts';
21	import { directorySignalFetcher } from './fetchers/directorySignalFetcher.ts';
22	import { normaliseAll } from './normaliser.ts';
23	import { scoreLead } from './scorer.ts';
24	
25	// Endpoint registry — printed in diagnostics
26	export const SOURCE_ENDPOINTS: Record<string, string[]> = {
27	  ContractsFinder: [
28	    'GET  https://www.contractsfinder.service.gov.uk/Published/Notices/OCDS/Search',
29	  ],
30	  FTS: [
31	    'GET  https://www.find-tender.service.gov.uk/api/1.0/ocdsReleasePackages',
32	  ],
33	  PlanningData: [
34	    'GET  https://www.planning.data.gov.uk/entity.json  (geo: ?latitude=&longitude=&dataset=planning-permission&period=current)',
35	    'GET  https://www.planning.data.gov.uk/entity.json  (postcode: ?q={outward}&dataset=planning-permission&period=current)',
36	  ],
37	  DirectorySignal: [
38	    '(internal structured dataset — no HTTP call)',
39	  ],
40	};
41	
42	export interface ScanOptions {
43	  postcode: string;
44	  trade?: string;
45	  tier?: 'free' | 'paid';
46	}
47	
48	export async function scan(opts: ScanOptions): Promise<ScanResult> {
49	  const { postcode, trade = 'all', tier = 'free' } = opts;
50	
51	  // 1. Resolve postcode
52	  const pcInfo = await lookupPostcode(postcode);
53	  const { outward, region } = pcInfo;
54	
55	  // 2. Run all sources concurrently — failures are caught internally
56	  const [cfResult, planningResult] = await Promise.allSettled([
57	    contractsFetcher(trade),
58	    planningDataFetcher(outward, region, trade, pcInfo.latitude, pcInfo.longitude),
59	  ]);
60	
61	  const dirResult = directorySignalFetcher(region, trade, outward); // sync
62	
63	  // 3. Collect raw leads + merge stats
64	  const allRaw = [
65	    ...(cfResult.status === 'fulfilled' ? cfResult.value.leads : []),
66	    ...(planningResult.status === 'fulfilled' ? planningResult.value.leads : []),
67	    ...dirResult.leads,
68	  ];
69	
70	  const mergedStats: Record<string, SourceStats> = {};
71	
72	  if (cfResult.status === 'fulfilled') {
73	    Object.assign(mergedStats, cfResult.value.stats);
74	  } else {
75	    mergedStats['ContractsFinder'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'ContractsFinder settled as rejected' };
76	    mergedStats['FTS'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'FTS settled as rejected' };
77	  }
78	
79	  if (planningResult.status === 'fulfilled') {
80	    Object.assign(mergedStats, planningResult.value.stats);
81	  } else {
82	    mergedStats['PlanningData'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'Planning settled as rejected' };
83	  }
84	
85	  Object.assign(mergedStats, dirResult.stats);
86	
87	  // 4. Normalise
88	  const normalised: Lead[] = normaliseAll(allRaw, trade);
89	
90	  // 5. Deduplicate by id
