4	/**
5	 * Score each lead 0–100.
6	 *
7	 * Factors:
8	 *  - source confidence        (0–30)
9	 *  - urgency                  (0–25)
10	 *  - region match             (0–20)
11	 *  - contact signal           (0–15)
12	 *  - value bracket            (0–10)
13	 */
14	export function scoreLead(lead: Lead, userRegion: string): number {
15	  let score = 0;
16	
17	  // Source confidence (max 30)
18	  score += Math.round((lead.sourceConfidence / 100) * 30);
19	
20	  // Urgency (max 25)
21	  if (lead.urgency === 'high')   score += 25;
22	  if (lead.urgency === 'medium') score += 15;
23	  if (lead.urgency === 'low')    score += 5;
24	
25	  // Region match (max 20)
26	  const sim = regionSimilarity(lead.location, userRegion);
27	  score += Math.round(sim * 20);
28	
29	  // Contact signal (max 15)
30	  if (lead.contactSignal === 'strong') score += 15;
31	  if (lead.contactSignal === 'weak')   score += 8;
32	
33	  // Value bracket (max 10) — sweet spot £5k–£200k
34	  const raw = parseValueToMidpoint(lead.estimatedValue);
35	  if (raw >= 5_000 && raw <= 200_000)   score += 10;
36	  else if (raw >= 1_000 && raw < 5_000) score += 5;
37	  else if (raw > 200_000)               score += 3;
38	
39	  return Math.min(score, 100);
40	}
41	
42	function parseValueToMidpoint(val: string): number {
43	  if (!val || val === 'POA') return 0;
44	  const nums = val.replace(/[£,]/g, '').match(/[\d.]+[kKmM]?/g) ?? [];
45	  const parse = (s: string): number => {
46	    const n = parseFloat(s);
47	    if (s.endsWith('M') || s.endsWith('m')) return n * 1_000_000;
48	    if (s.endsWith('K') || s.endsWith('k')) return n * 1_000;
49	    return n;
50	  };
51	  const values = nums.map(parse).filter(n => n > 0);
52	  if (!values.length) return 0;
53	  return values.reduce((a, b) => a + b, 0) / values.length;
54	}
